#include <bits/stdc++.h>
using namespace std;
int n,a[21][21];
long long f[1<<20][21];
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		for(int j=1;j<=n;j++)
			scanf("%d",&a[i][j]);
	memset(f,127,sizeof(f));
	for(int i=1;i<1<<n;i++)
		for(int j=1;j<=n;j++)
			if(((1<<(j-1))&i) && (i&1)){
				if(i==(1<<(j-1)))
					f[i][j]=0;
				else
					for(int k=1;k<=n;k++)
						if(k!=j && (1<<(k-1))&i)
							f[i][j]=min(f[i][j],f[i-(1<<(j-1))][k]+a[j][k]);
			}
	printf("%lld",f[(1<<n)-1][n]);
	return 0;
}
